class ProductionLoggingSystem private constructor(private val context: Context) {

    companion object {
        @Volatile
        private var instance: ProductionLoggingSystem? = null

        fun initialize(context: Context): ProductionLoggingSystem {
            return instance ?: synchronized(this) {
                instance ?: ProductionLoggingSystem(context.applicationContext).also {
                    instance = it
                    it.setupTimber()
                }
            }
        }

        fun getInstance(): ProductionLoggingSystem {
            return instance ?: throw IllegalStateException("ProductionLoggingSystem not initialized")
        }
    }

    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
    private val logFile: File by lazy {
        File(context.getExternalFilesDir(null), "production_logs.txt")
    }

    private fun setupTimber() {
        Timber.plant(ProductionTree())
        Timber.plant(FileLoggingTree())
    }

    inner class ProductionTree : Timber.DebugTree() {
        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            val priorityString = when (priority) {
                Log.VERBOSE -> "VERBOSE"
                Log.DEBUG -> "DEBUG"
                Log.INFO -> "INFO"
                Log.WARN -> "WARN"
                Log.ERROR -> "ERROR"
                Log.ASSERT -> "ASSERT"
                else -> "UNKNOWN"
            }

            val timestamp = dateFormat.format(Date())
            val logMessage = "[$timestamp] [$priorityString] [${tag ?: "NO_TAG"}] $message"

            Log.println(priority, tag ?: "ProductionLog", message)

            if (t != null) {
                Log.println(priority, tag ?: "ProductionLog", getStackTraceString(t))
            }
        }

        override fun createStackElementTag(element: StackTraceElement): String {
            return "${element.className}.${element.methodName}:${element.lineNumber}"
        }
    }

    inner class FileLoggingTree : Timber.Tree() {
        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            try {
                val timestamp = dateFormat.format(Date())
                val priorityString = when (priority) {
                    Log.VERBOSE -> "VERBOSE"
                    Log.DEBUG -> "DEBUG"
                    Log.INFO -> "INFO"
                    Log.WARN -> "WARN"
                    Log.ERROR -> "ERROR"
                    Log.ASSERT -> "ASSERT"
                    else -> "UNKNOWN"
                }

                val logMessage = StringBuilder()
                logMessage.append("[$timestamp] [$priorityString] [${tag ?: "NO_TAG"}] $message\n")

                if (t != null) {
                    logMessage.append(getStackTraceString(t))
                    logMessage.append("\n")
                }

                FileWriter(logFile, true).use { writer ->
                    writer.append(logMessage.toString())
                }
            } catch (e: Exception) {
                Log.e("FileLoggingTree", "Error writing to log file", e)
            }
        }
    }

    private fun getStackTraceString(throwable: Throwable): String {
        val sw = StringWriter()
        val pw = PrintWriter(sw)
        throwable.printStackTrace(pw)
        return sw.toString()
    }

    fun logAuthenticationAttempt(
        username: String,
        success: Boolean,
        failureReason: String? = null,
        ipAddress: String? = null,
        deviceInfo: String? = null
    ) {
        val logData = JSONObject().apply {
            put("event_type", "AUTHENTICATION_ATTEMPT")
            put("timestamp", dateFormat.format(Date()))
            put("username", username)
            put("success", success)
            put("ip_address", ipAddress ?: "unknown")
            put("device_info", deviceInfo ?: "unknown")
            if (!success && failureReason != null) {
                put("failure_reason", failureReason)
            }
        }

        if (success) {
            Timber.i("AUTH_SUCCESS: %s", logData.toString(2))
        } else {
            Timber.w("AUTH_FAILURE: %s", logData.toString(2))
        }
    }

    fun logDatabaseQuery(
        query: String,
        parameters: Map<String, Any?>? = null,
        executionTimeMs: Long? = null,
        rowsAffected: Int? = null,
        error: Throwable? = null
    ) {
        val logData = JSONObject().apply {
            put("event_type", "DATABASE_QUERY")
            put("timestamp", dateFormat.format(Date()))
            put("query", query)
            
            if (parameters != null && parameters.isNotEmpty()) {
                val paramsJson = JSONObject()
                parameters.forEach { (key, value) ->
                    paramsJson.put(key, value?.toString() ?: "null")
                }
                put("parameters", paramsJson)
            }
            
            executionTimeMs?.let { put("execution_time_ms", it) }
            rowsAffected?.let { put("rows_affected", it) }
            
            if (error != null) {
                put("error", error.message ?: "Unknown error")
                put("error_type", error.javaClass.simpleName)
            }
        }

        if (error != null) {
            Timber.e(error, "DB_QUERY_ERROR: %s", logData.toString(2))
        } else {
            Timber.v("DB_QUERY: %s", logData.toString(2))
        }
    }

    fun logApiRequest(
        method: String,
        url: String,
        headers: Map<String, String>? = null,
        requestBody: String? = null,
        responseCode: Int? = null,
        responseBody: String? = null,
        durationMs: Long? = null,
        error: Throwable? = null
    ) {
        val logData = JSONObject().apply {
            put("event_type", "API_REQUEST")
            put("timestamp", dateFormat.format(Date()))
            put("method", method)
            put("url", url)
            
            if (headers != null && headers.isNotEmpty()) {
                val headersJson = JSONObject()
                headers.forEach { (key, value) ->
                    headersJson.put(key, sanitizeHeader(key, value))
                }
                put("headers", headersJson)
            }
            
            requestBody?.let { 
                put("request_body", sanitizeBody(it))
            }
            
            responseCode?.let { put("response_code", it) }
            
            responseBody?.let { 
                put("response_body", sanitizeBody(it))
            }
            
            durationMs?.let { put("duration_ms", it) }
            
            if (error != null) {
                put("error", error.message ?: "Unknown error")
                put("error_type", error.javaClass.simpleName)
            }
        }

        if (error != null) {
            Timber.e(error, "API_REQUEST_ERROR: %s", logData.toString(2))
        } else if (responseCode != null && responseCode >= 400) {
            Timber.w("API_REQUEST_FAILED: %s", logData.toString(2))
        } else {
            Timber.d("API_REQUEST: %s", logData.toString(2))
        }
    }

    private fun sanitizeHeader(key: String, value: String): String {
        val sensitiveHeaders = listOf("authorization", "api-key", "token", "password", "secret")
        return if (sensitiveHeaders.any { key.lowercase().contains(it) }) {
            "***REDACTED***"
        } else {
            value
        }
    }

    private fun sanitizeBody(body: String): String {
        return try {
            val maxLength = 5000
            if (body.length > maxLength) {
                body.substring(0, maxLength) + "... (truncated)"
            } else {
                body
            }
        } catch (e: Exception) {
            "Error sanitizing body: ${e.message}"
        }
    }

    fun logException(
        exception: Throwable,
        context: String? = null,
        additionalData: Map<String, Any?>? = null
    ) {
        val logData = JSONObject().apply {
            put("event_type", "EXCEPTION")
            put("timestamp", dateFormat.format(Date()))
            put("exception_type", exception.javaClass.simpleName)
            put("exception_message", exception.message ?: "No message")
            put("stack_trace", getStackTraceString(exception))
            
            context?.let { put("context", it) }
            
            if (additionalData != null && additionalData.isNotEmpty()) {
                val dataJson = JSONObject()
                additionalData.forEach { (key, value) ->
                    dataJson.put(key, value?.toString() ?: "null")
                }
                put("additional_data", dataJson)
            }
            
            exception.cause?.let {
                put("cause_type", it.javaClass.simpleName)
                put("cause_message", it.message ?: "No message")
            }
        }

        Timber.e(exception, "EXCEPTION: %s", logData.toString(2))
    }

    fun logUserAction(
        action: String,
        screen: String? = null,
        details: Map<String, Any?>? = null
    ) {
        val logData = JSONObject().apply {
            put("event_type", "USER_ACTION")
            put("timestamp", dateFormat.format(Date()))
            put("action", action)
            screen?.let { put("screen", it) }
            
            if (details != null && details.isNotEmpty()) {
                val detailsJson = JSONObject()
                details.forEach { (key, value) ->
                    detailsJson.put(key, value?.toString() ?: "null")
                }
                put("details", detailsJson)
            }
        }

        Timber.i("USER_ACTION: %s", logData.toString(2))
    }

    fun logPerformanceMetric(
        metricName: String,
        value: Long,
        unit: String = "ms",
        additionalInfo: Map<String, Any?>? = null
    ) {
        val logData = JSONObject().apply {
            put("event_type", "PERFORMANCE_METRIC")
            put("timestamp", dateFormat.format(Date()))
            put("metric_name", metricName)
            put("value", value)
            put("unit", unit)
            
            if (additionalInfo != null && additionalInfo.isNotEmpty()) {
                val infoJson = JSONObject()
                additionalInfo.forEach { (key, value) ->
                    infoJson.put(key, value?.toString() ?: "null")
                }
                put("additional_info", infoJson)
            }
        }

        Timber.d("PERFORMANCE: %s", logData.toString(2))
    }

    fun getLogFile(): File = logFile

    fun clearLogs() {
        try {
            logFile.delete()
            Timber.i("Logs cleared successfully")
        } catch (e: Exception) {
            Timber.e(e, "Error clearing logs")
        }
    }

    fun getLogFileContent(): String {
        return try {
            if (logFile.exists()) {
                logFile.readText()
            } else {
                "No logs available"
            }
        } catch (e: Exception) {
            Timber.e(e, "Error reading log file")
            "Error reading logs: ${e.message}"
        }
    }
